import fs from 'node:fs';
import path from 'node:path';

// Load the near-duplicate redirect map (generated by
// scripts/ihatecbts_dedupe_sets_pass7.mjs). 301s the duplicate slug to the
// canonical one so SEO consolidates and visitors land on the single
// authoritative version of each Q&A set.
function loadDedupeRedirects() {
  const file = path.join(process.cwd(), 'scripts', 'dedupe_redirects.json');
  if (!fs.existsSync(file)) return [];
  try {
    const data = JSON.parse(fs.readFileSync(file, 'utf8'));
    return (data.redirects || []).map(r => ({
      source: `/answers/${r.from}`,
      destination: `/answers/${r.to}`,
      permanent: true,
    }));
  } catch {
    return [];
  }
}

/** @type {import('next').NextConfig} */
const nextConfig = {
  output: 'standalone',
  experimental: {
    serverComponentsExternalPackages: ['pdf-parse'],
  },
  async headers() {
    return [
      {
        source: '/api/ext/:path*',
        headers: [
          { key: 'Access-Control-Allow-Origin', value: '*' },
          { key: 'Access-Control-Allow-Methods', value: 'POST, OPTIONS' },
          { key: 'Access-Control-Allow-Headers', value: 'Content-Type' },
        ],
      },
    ];
  },
  async redirects() {
    return loadDedupeRedirects();
  },
};

export default nextConfig;
